'use client';

import React, { useState, useEffect, useMemo } from 'react';
import AdminUsers from '@/components/dashboard/admin/AdminUsers';
import VerifiedUsers from '@/components/dashboard/admin/VerifiedUsers';
import SuspendedUsers from '@/components/dashboard/admin/SuspendedUsers';
import UserReports from '@/components/dashboard/admin/UserReports';

// Sidebar and other layout components would be here

export default function DashboardPage() {
  const [activeTab, setActiveTab] = useState('all');

  const renderContent = () => {
    switch (activeTab) {
      case 'all':
        return <AdminUsers />;
      case 'verified':
        return <VerifiedUsers />;
      case 'suspended':
        return <SuspendedUsers />;
      case 'reports':
        return <UserReports />;
      default:
        return <AdminUsers />;
    }
  };

  return (
    <div className="flex">
        <aside className="w-64 bg-white border-r">
            <div className="p-4">
                <h1 className="text-2xl font-bold">Admin</h1>
                <nav className="mt-8">
                    <ul>
                        <li><button onClick={() => setActiveTab('all')} className="w-full text-left p-2 rounded-lg hover:bg-gray-100">All Users</button></li>
                        <li><button onClick={() => setActiveTab('verified')} className="w-full text-left p-2 rounded-lg hover:bg-gray-100">Verified Users</button></li>
                        <li><button onClick={() => setActiveTab('suspended')} className="w-full text-left p-2 rounded-lg hover:bg-gray-100">Suspended</button></li>
                        <li><button onClick={() => setActiveTab('reports')} className="w-full text-left p-2 rounded-lg hover:bg-gray-100">Reports</button></li>
                    </ul>
                </nav>
            </div>
        </aside>
        <main className="flex-1">
            {renderContent()}
        </main>
    </div>
  );
}