'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { getUsers } from '@/lib/store';
import { User } from '@/lib/types';
import { Search, MoreHorizontal, FileText, Filter, ShieldAlert, ChevronLeft, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from '@/lib/utils';

const Card = ({ title, value, icon, accent }: any) => {
    const themeMap: any = {
      red: { bg: 'bg-gradient-to-br from-red-400 to-red-600' },
      yellow: { bg: 'bg-gradient-to-br from-yellow-400 to-yellow-600' },
      orange: { bg: 'bg-gradient-to-br from-orange-400 to-orange-600' },
      green: { bg: 'bg-gradient-to-br from-green-400 to-green-600' },
    };
    const theme = themeMap[accent] || themeMap.red;
    return (
      <div className={`relative rounded-2xl p-5 text-white overflow-hidden shadow-lg ${theme.bg}`}>
        <div className="absolute top-4 right-4 h-10 w-10 bg-white/20 rounded-full flex items-center justify-center">{icon}</div>
        <p className="text-sm font-medium text-white/80">{title}</p>
        <p className="text-4xl font-bold mt-2">{value}</p>
      </div>
    );
};

export default function UserReports() {
  const [allUsers, setAllUsers] = useState<Record<string, User>>({});
  const [searchQuery, setSearchQuery] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;
  const [activeTab, setActiveTab] = useState('open');

  useEffect(() => {
    const usersData = getUsers();
    setAllUsers(usersData || {});
  }, []);

  const reportUsers = useMemo(() => {
    return Object.values(allUsers).filter(u => u.isRejected || u.status === 'blocked');
  }, [allUsers]);

  const filteredUsers = useMemo(() => {
    return reportUsers.filter(u =>
      u.firstName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.lastName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.email?.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [reportUsers, searchQuery]);

  const totalPages = Math.max(1, Math.ceil(filteredUsers.length / itemsPerPage));
  const paginatedUsers = filteredUsers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const stats = {
      openReports: reportUsers.length,
      investigating: 21,
      critical: 6,
      resolvedToday: 34,
  };

  return (
    <div className="w-full bg-gray-50/50 min-h-screen p-4 md:p-8 font-sans">
        <header className="mb-8">
            <div className="text-sm text-gray-500 mb-2">Users / <span className="font-medium text-gray-700">User Reports</span></div>
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900">User Reports</h1>
                    <p className="mt-1 text-gray-600">Fraud, abuse, spam and fake booking reports filed by users and the abuse detection engine.</p>
                </div>
                <Button variant="outline" className="bg-white"><FileText size={14} className="mr-2"/> Export</Button>
            </div>
        </header>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            <Card title="OPEN REPORTS" value={stats.openReports.toLocaleString()} icon={<ShieldAlert size={20} />} accent="red" />
            <Card title="INVESTIGATING" value={stats.investigating} icon={<ShieldAlert size={20} />} accent="yellow" />
            <Card title="CRITICAL" value={stats.critical} icon={<ShieldAlert size={20} />} accent="orange" />
            <Card title="RESOLVED TODAY" value={stats.resolvedToday} icon={<ShieldAlert size={20} />} accent="green" />
        </div>

        <div className="bg-white rounded-xl shadow-md">
            <div className="p-4 flex justify-between items-center border-b border-gray-200">
                 <div className="flex items-center gap-2">
                    <button onClick={() => setActiveTab('all')} className={cn('px-4 py-2 rounded-lg text-sm font-semibold', activeTab === 'all' ? 'bg-gray-100' : 'text-gray-500')}>All</button>
                    <button onClick={() => setActiveTab('open')} className={cn('px-4 py-2 rounded-lg text-sm font-semibold', activeTab === 'open' ? 'bg-gray-100' : 'text-gray-500')}>Open</button>
                    <button onClick={() => setActiveTab('investigating')} className={cn('px-4 py-2 rounded-lg text-sm font-semibold', activeTab === 'investigating' ? 'bg-gray-100' : 'text-gray-500')}>Investigating</button>
                    <button onClick={() => setActiveTab('resolved')} className={cn('px-4 py-2 rounded-lg text-sm font-semibold', activeTab === 'resolved' ? 'bg-gray-100' : 'text-gray-500')}>Resolved</button>
                    <button onClick={() => setActiveTab('dismissed')} className={cn('px-4 py-2 rounded-lg text-sm font-semibold', activeTab === 'dismissed' ? 'bg-gray-100' : 'text-gray-500')}>Dismissed</button>
                </div>
                <div className="flex items-center gap-4">
                    <div className="relative w-full max-w-xs">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <Input
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            placeholder="Search reports..."
                            className="pl-9 w-full"
                        />
                    </div>
                    <Button variant="outline" className="bg-white"><Filter size={14} className="mr-2"/> Filter</Button>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-left">
                    <thead>
                        <tr className="text-xs font-semibold text-gray-500 uppercase bg-gray-50">
                            <th className="px-6 py-3">Report ID</th>
                            <th className="px-6 py-3">Reported User</th>
                            <th className="px-6 py-3">Filed By</th>
                            <th className="px-6 py-3">Type</th>
                            <th className="px-6 py-3">Severity</th>
                            <th className="px-6 py-3">Status</th>
                            <th className="px-6 py-3">Filed</th>
                            <th className="px-6 py-3"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200">
                        {paginatedUsers.map(u => (
                            <tr key={u.email} className="hover:bg-gray-50">
                                <td className="px-6 py-4 text-gray-600">REP-4400</td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-gray-200"></div>
                                        <div>
                                            <div className="font-bold text-gray-800">{u.firstName} {u.lastName}</div>
                                            <div className="text-sm text-gray-500">{u.email}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-gray-600">USR-10200</td>
                                <td className="px-6 py-4 text-gray-600">Fraud</td>
                                <td className="px-6 py-4"><Badge variant="outline" className="border-yellow-300 text-yellow-700">Low</Badge></td>
                                <td className="px-6 py-4"><Badge variant="default" className="bg-blue-100 text-blue-700">Open</Badge></td>
                                <td className="px-6 py-4 text-gray-600">1h ago</td>
                                <td className="px-6 py-4 text-right">
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild><Button variant="ghost" size="icon"><MoreHorizontal size={20} /></Button></DropdownMenuTrigger>
                                        <DropdownMenuContent align="end">
                                            <DropdownMenuItem>View Report</DropdownMenuItem>
                                            <DropdownMenuItem>Take Action</DropdownMenuItem>
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            <div className="px-6 py-4 flex items-center justify-between border-t border-gray-200">
                <span className="text-sm text-gray-500">Showing {paginatedUsers.length} of {filteredUsers.length} reports</span>
                <div className="flex items-center gap-1">
                    <Button variant="ghost" size="icon" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1}><ChevronLeft size={18} /></Button>
                    <Button variant="ghost" size="icon" onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages}><ChevronRight size={18} /></Button>
                </div>
            </div>
        </div>
    </div>
  );
}